"import os
import re
from pathlib import Path

def replace_in_file(path):
    with open(path, 'r') as f:
        content = f.read()

    def repl(match):
        word = match.group(0)
        if word.istitle():
            return "Cuecifer"
        elif word.isupper():
            return "CUECIFER"
        else:
            return "cuecifer"

    new_content = re.sub(r'magikbox', repl, content, flags=re.IGNORECASE)

    if new_content != content:
        with open(path, 'w') as f:
            f.write(new_content)
        print(f"Updated {path}")

    if 'magikbox' in path.name.lower():
        new_name = re.sub(r'magikbox', repl, path.name, flags=re.IGNORECASE)
        new_path = path.with_name(new_name)
        os.rename(path, new_path)
        print(f"Renamed {path.name} -> {new_path.name}")

for root, _, files in os.walk('/Users/g/Projects/taghag/docs'):
    for f in files:
        if f.endswith('.md'):
            replace_in_file(Path(root) / f)

replace_in_file(Path('/Users/g/Projects/taghag/README.md'))
"

